281	func dirHash(t *testing.T, root string) string {
282		t.Helper()
283		h := sha256.New()
284		walked := []string{}
285		if err := filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
286			if err != nil {
287				return err
288			}
289			if info.IsDir() {
290				return nil
291			}
292			rel, _ := filepath.Rel(root, path)
293			walked = append(walked, rel)
294			return nil
295		}); err != nil {
296			t.Fatal(err)
297		}
298		// Stable order.
299		for _, rel := range walked {
300			f, err := os.Open(filepath.Join(root, rel))
301			if err != nil {
302				t.Fatal(err)
303			}
304			_, _ = io.WriteString(h, rel+"\x00")
305			_, _ = io.Copy(h, f)
306			_ = f.Close()
307		}
308		return hex.EncodeToString(h.Sum(nil))
309	}
